args.sparql:
SELECT ?president ?presidentLabel ?age WHERE {
  ?president wdt:P39 wd:Q5708511;
          wdt:P569 ?birthDate;
          wdt:P570 ?deathDate;
          wdt:P26 ?causeOfDeath.
  VALUES ?causeOfDeath { wd:Q541528 wd:Q4933634 }
  BIND(math:year(?deathDate) - math:year(?birthDate) AS ?age)
  ?president rdfs:label ?presidentLabel.
  FILTER(LANG(?presidentLabel) = 'en')
}

